const raw = $input.first().json;
const data = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
return [{ json: data }];

let submitterEmail = '';
try { submitterEmail = ($('Новый ответ на форму').first()?.json['Email Address'] || '').toLowerCase().trim(); } catch(e) {}
const rows = $input.all();
const found = rows.find(row => (row.json['Email'] || '').toLowerCase().trim() === submitterEmail);
return [{ json: { allowed: !!found, submitterEmail } }];

const nomerDogovora = ($('Новый ответ на форму').first()?.json['Номер договора'] || '').trim();
const dataDogovora  = ($('Новый ответ на форму').first()?.json['Дата договора']  || '').trim();
if (!nomerDogovora) throw new Error('Для первого приложения укажите «Номер договора» в форме.');
if (!dataDogovora)  throw new Error('Для первого приложения укажите «Дата договора» в форме.');
return [{ json: { nomerDogovora, dataDogovora, nomerPrilozhenia: '1' } }];

const formUrl = ($('Новый ответ на форму').first()?.json['Ссылка на предыдущее приложение'] || '').trim();
const match = formUrl.match(/\/document\/d\/([a-zA-Z0-9_-]+)/)
           || formUrl.match(/\/file\/d\/([a-zA-Z0-9_-]+)/)
           || formUrl.match(/[?&]id=([a-zA-Z0-9_-]+)/);
if (!match) throw new Error('Не удалось извлечь ID из ссылки. Проверьте ссылку на предыдущее приложение.');
return [{ json: { ...$input.item.json, prevDocId: match[1] } }];

// Рекурсивный экстрактор текста включая таблицы (ячейки строки разделяются \t)
function extractText(content) {
  if (!Array.isArray(content)) return '';
  return content.map(el => {
    if (el.paragraph) return (el.paragraph.elements || []).map(e => e.textRun?.content || '').join('');
    if (el.table) {
      return (el.table.tableRows || []).map(row =>
        (row.tableCells || []).map(cell =>
          extractText(cell.content || []).replace(/\n+/g, ' ').trim()
        ).join('\t')
      ).join('\n');
    }
    return '';
  }).join('\n');
}

let text = '';
if (typeof $input.item.json.content === 'string') {
  text = $input.item.json.content;
} else {
  text = extractText($input.item.json.body?.content || []);
}

const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
const docRef = $input.item.json.title || $input.item.json.documentId || 'неизвестный документ';

// === Номер приложения ===
// Принимаем «Приложение № 1», «Приложение №1», «Приложение 1»
// Фолбэк: из названия документа
const matchNomer =
  text.match(/Приложение\s*№\s*(\d+)/i) ||
  text.match(/Приложение\s+(\d+)(?=[\s\-–—,.]|$)/i) ||
  (docRef + ' ').match(/Приложение\s*(?:№\s*)?(\d+)(?=[\s\-–—,.]|$)/i);
if (!matchNomer) throw new Error('Не найден номер приложения в документе: ' + docRef);

// === Номер и дата основного договора ===
// Дата: «15 января 2024 г.» ИЛИ «15.01.2024» ИЛИ «01/01/2024»
const dateRu = '[«"]?\\d+[»"]?\\s+\\S+\\s+\\d{4}\\s*(?:г\\.?|года)?';
const dateDMY = '\\d{2}[./]\\d{2}[./]\\d{4}';
const dateAny = '(?:' + dateRu + '|' + dateDMY + ')';
// «к Договору [слова] № X от DATE»
const re1 = new RegExp('к\\s+Договор[уа]?\\s*(?:(?:\\S+\\s+){0,6})?№\\s*(\\S+)\\s+от\\s+(' + dateAny + ')', 'i');
// «Договора/Договору/Договор № X от DATE» (без «к»)
const re2 = new RegExp('Договор[аеуом]?\\s*(?:(?:\\S+\\s+){0,4})?№\\s*(\\S+)\\s+от\\s+(' + dateAny + ')', 'i');
const matchDogovor = text.match(re1) || text.match(re2);
if (!matchDogovor) throw new Error('Не найдены номер и дата договора в документе: ' + docRef + '. Ожидается текст вида «к Договору № X от DD.MM.YYYY» или «к Договору № X от 15 января 2024 г.»');

// Должность подписанта контрагента из «в лице ...»
let signatoryTitle = '';
const titleMatch = text.match(/в\s+лице\s+(.+?)\s+[А-ЯЁ][а-яё]+(?:\s+[А-ЯЁ]\.[А-ЯЁ]\.| [А-ЯЁ][а-яё]+ [А-ЯЁ][а-яё]+)/i);
if (titleMatch) signatoryTitle = titleMatch[1].trim();

// === Название организации контрагента ===
// Стратегия 1: таб-строка где правая ячейка содержит «М-Спринт» → левая = контрагент
let clientName = '';
for (const line of lines) {
  const parts = line.split('\t');
  if (parts.length >= 2) {
    const right = parts[parts.length - 1];
    const left = parts[0];
    if (/М[\-.]?Спринт/i.test(right) && /(?:ООО|АО|ИП|ПАО|ЗАО)/i.test(left)) {
      clientName = left.trim();
      break;
    }
  }
}
// Стратегия 2: любой ООО/АО/ИП «...» который не М-Спринт
if (!clientName) {
  for (const m of text.matchAll(/((?:ООО|АО|ИП|ПАО|ЗАО|НКО)\s*[«"][^»"\n]{2,60}[»"])/g)) {
    if (!/М.Спринт/i.test(m[1])) { clientName = m[1].trim(); break; }
  }
}

// === ФИО подписанта контрагента (формат «Фамилия И.О.») ===
let signatoryName = '';
const fioRe = /^([А-ЯЁ][а-яё]+\s+[А-ЯЁ]\.[А-ЯЁ]\.)$/;
// Таб-строка где обе ячейки — это ФИО → левая = контрагент
for (const line of lines) {
  const parts = line.split('\t');
  if (parts.length >= 2 && fioRe.test(parts[0].trim()) && fioRe.test(parts[parts.length - 1].trim())) {
    signatoryName = parts[0].trim();
    break;
  }
}
// Фолбэк: первое ФИО после названия контрагента в тексте
if (!signatoryName && clientName) {
  const pos = text.indexOf(clientName);
  if (pos >= 0) {
    const m = text.substring(pos).match(/([А-ЯЁ][а-яё]+\s+[А-ЯЁ]\.[А-ЯЁ]\.)/);
    if (m) signatoryName = m[1].trim();
  }
}

// Доп. стратегии для должности — из блока подписей
const titleRe = /^(Генеральный директор|Директор|Президент|Председатель|Руководитель)/i;
if (!signatoryTitle) {
  for (const line of lines) {
    const parts = line.split('\t');
    if (parts.length >= 2) {
      const right = parts[parts.length - 1].trim();
      const left  = parts[0].trim();
      const rm = right.match(titleRe);
      const lm = left.match(titleRe);
      if (rm && lm) {
        signatoryTitle = rm[1];
        break;
      }
    }
  }
}
if (!signatoryTitle && clientName) {
  for (let i = 1; i < lines.length; i++) {
    if (lines[i].split('\t').some(p => p.trim() === clientName)) {
      const prevParts = lines[i - 1].split('\t');
      const candidate = (prevParts[prevParts.length - 1] || prevParts[0]).trim();
      const cm = candidate.match(titleRe);
      if (cm) signatoryTitle = cm[1];
      break;
    }
  }
}
return [{
  json: {
    nomerDogovora:    matchDogovor[1].trim(),
    dataDogovora:     matchDogovor[2].trim(),
    nomerPrilozhenia: String(parseInt(matchNomer[1]) + 1),
    signatoryTitle,
    clientName,
    signatoryName
  }
}];

let url = '';
try { url = $('Новый ответ на форму').first()?.json['Ссылка на файл реквизитов клиента'] || ''; } catch(e) {}
const match = url.match(/\/document\/d\/([a-zA-Z0-9_-]+)/);
if (!match) throw new Error('Неверная ссылка на файл реквизитов: ' + url);
return [{ json: { requisitesDocId: match[1] } }];

function extractText(content) {
  if (!Array.isArray(content)) return '';
  return content.map(el => {
    if (el.paragraph) return (el.paragraph.elements || []).map(e => e.textRun?.content || '').join('');
    if (el.table) {
      return (el.table.tableRows || []).map(row =>
        (row.tableCells || []).map(cell =>
          extractText(cell.content || []).replace(/\n+/g, ' ').trim()
        ).join('\t')
      ).join('\n');
    }
    return '';
  }).join('\n');
}

let text = '';
if (typeof $input.item.json.content === 'string') {
  text = $input.item.json.content;
} else {
  text = extractText($input.item.json.body?.content || []);
}

const lines = text.split('\n').map(l => l.trim()).filter(Boolean);

function getField(name) {
  const low = name.toLowerCase();
  for (const line of lines) {
    const parts = line.split('\t');
    if (parts.length >= 2 && parts[0].trim().toLowerCase() === low) return parts.slice(1).join('\t').trim();
  }
  const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp('^' + escaped + '\\s*:\\s*(.+)', 'i');
  for (const line of lines) { const m = line.match(re); if (m && m[1].trim()) return m[1].trim(); }
  for (let i = 0; i < lines.length - 1; i++) { if (lines[i].toLowerCase() === low) return lines[i + 1].split('\t')[0].trim(); }
  return '';
}

let fullName = getField('Сокращенное название') || getField('Сокращённое название')
            || getField('Краткое наименование') || getField('Краткое название')
            || getField('Полное название') || getField('Полное наименование')
            || getField('Наименование') || getField('Название')
            || getField('Организация') || getField('Исполнитель')
            || getField('Заказчик') || getField('Клиент');

if (!fullName) {
  const m = text.match(/((?:ООО|ОАО|ЗАО|АО|ИП|ПАО|НКО|ГУП|МУП)\s*[«"][^»"\n]{2,60}[»"])/);
  if (m) fullName = m[1].trim();
}
if (!fullName) {
  const header = lines.slice(0, 5).join(' ');
  const m = header.match(/((?:ООО|ОАО|ЗАО|АО|ИП|ПАО|НКО)\s+[А-ЯЁ«"][А-ЯЁа-яёЁ\-«»"" ]+)/);
  if (m) fullName = m[1].trim();
}

let signatoryRaw = getField('ФИО подписанта') || getField('ФИО') || getField('Подписант')
                || getField('Генеральный директор') || getField('Директор')
                || getField('Руководитель') || getField('Президент') || getField('Председатель');

if (!signatoryRaw) {
  for (let i = 0; i < lines.length - 1; i++) {
    if (/^(генеральный директор|директор|руководитель|президент|подписант)/i.test(lines[i].split('\t')[0])) {
      const parts = lines[i].split('\t');
      signatoryRaw = parts.length >= 2 ? parts[1] : (lines[i].split(':')[1]?.trim() || lines[i + 1] || '');
      break;
    }
  }
}
if (!signatoryRaw) {
  const m = text.match(/([А-ЯЁ][а-яё]+ [А-ЯЁ][а-яё]+ [А-ЯЁ][а-яё]+)/);
  if (m) signatoryRaw = m[1];
}
if (signatoryRaw) {
  const fioOnly = signatoryRaw.match(/^([А-ЯЁа-яёЁ]+(?:[\s\-][А-ЯЁа-яёЁ]+){1,2})/);
  if (fioOnly) signatoryRaw = fioOnly[1].trim();
}

let signatoryTitle = getField('Должность') || getField('Должность подписанта') || '';
if (!signatoryTitle) {
  const titles = ['Генеральный директор', 'Директор', 'Президент', 'Руководитель', 'Председатель'];
  for (const t of titles) { if (getField(t)) { signatoryTitle = t; break; } }
}
if (!signatoryTitle) {
  const m = lines.find(l => /^(генеральн\w*\s+директор\w*|директор\w*|президент\w*|руководитель\w*|председатель\w*)/i.test(l.split('\t')[0]));
  if (m) { const ci = m.indexOf(':'); signatoryTitle = ci > 0 ? m.substring(0, ci).trim() : m.split('\t')[0].trim(); }
}

if (!fullName) throw new Error('Не найдено название организации в документе реквизитов.');
if (!signatoryRaw) throw new Error('Не найдено ФИО подписанта в документе реквизитов.');

function formatFIO(fio) {
  const parts = fio.trim().split(/\s+/);
  if (parts.length >= 3) return parts[0] + ' ' + parts[1][0] + '.' + parts[2][0] + '.';
  if (parts.length === 2) return parts[0] + ' ' + parts[1][0] + '.';
  return fio;
}

return [{ json: { clientName: fullName, signatoryName: formatFIO(signatoryRaw), signatoryTitle } }];

// Данные договора: из предыдущего приложения или из формы (первое приложение)
let nomerDogovora = '', dataDogovora = '', nomerPrilozhenia = '1';
try {
  const d = $('Извлечь номер и дату договора').item.json;
  nomerDogovora    = d.nomerDogovora    || '';
  dataDogovora     = d.dataDogovora     || '';
  nomerPrilozhenia = d.nomerPrilozhenia || '1';
} catch(e) {}
if (!nomerDogovora) {
  try {
    const d = $('Данные первого приложения').item.json;
    nomerDogovora    = d.nomerDogovora || '';
    dataDogovora     = d.dataDogovora  || '';
    nomerPrilozhenia = '1';
  } catch(e) {}
}

// Данные контрагента: из предыдущего приложения или из реквизитов
let clientName = '', signatoryName = '', signatoryTitle = '';
try {
  const d = $('Извлечь номер и дату договора').item.json;
  if (d.clientName)     clientName     = d.clientName;
  if (d.signatoryName)  signatoryName  = d.signatoryName;
  if (d.signatoryTitle) signatoryTitle = d.signatoryTitle;
} catch(e) {}
if (!clientName || !signatoryTitle) {
  try {
    const d = $('Разобрать реквизиты').item.json;
    if (!clientName && d.clientName)       clientName    = d.clientName;
    if (!signatoryName && d.signatoryName) signatoryName = d.signatoryName;
    if (!signatoryTitle && d.signatoryTitle) signatoryTitle = d.signatoryTitle;
  } catch(e) {}
}

if (!nomerDogovora) throw new Error('Не удалось получить номер договора.');
if (!clientName) throw new Error('Не удалось получить название организации контрагента.');
if (!signatoryName) throw new Error('Не удалось получить ФИО подписанта контрагента.');

return [{ json: { nomerDogovora, dataDogovora, nomerPrilozhenia, clientName, signatoryName, signatoryTitle } }];

let service = '';
try { service = ($('Новый ответ на форму').first()?.json['Услуга'] || '').trim(); } catch(e) {}
const rows = $input.all();
const found = rows.find(row => (row.json['Услуга'] || '').trim() === service);
if (!found) return [{ json: { 'ID шаблона на Drive': null } }];
return [{ json: found.json }];

const MONTHS = ['января','февраля','марта','апреля','мая','июня','июля','августа','сентября','октября','ноября','декабря'];
function formatDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  if (isNaN(d)) return dateStr;
  return `${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()} г.`;
}
let formData = {};
try { formData = $('Новый ответ на форму').first()?.json || {}; } catch(e) {}

// Определяем ID документа-источника для поиска папки
let folderSourceDocId = '';
try { folderSourceDocId = $('Определить ID предыдущего приложения').item.json.prevDocId; } catch(e) {}
if (!folderSourceDocId) {
  try { folderSourceDocId = $('Извлечь ID документа реквизитов').item.json.requisitesDocId; } catch(e) {}
}
if (!folderSourceDocId) throw new Error('Не удалось определить ID документа для поиска папки.');

return [{ json: { dateApp: formatDate(formData['Дата приложения']), dateStart: formatDate(formData['Дата начала работ']), folderSourceDocId } }];

const nomerPrilozhenia = $('Собрать данные контрагента').item.json.nomerPrilozhenia;
const nomerDogovora    = $('Собрать данные контрагента').item.json.nomerDogovora;
const dataDogovora     = $('Собрать данные контрагента').item.json.dataDogovora;
const dateApp          = $('Форматировать даты').item.json.dateApp;
const dateStart        = $('Форматировать даты').item.json.dateStart;
const clientName       = $('Собрать данные контрагента').item.json.clientName;
const signatoryName    = $('Собрать данные контрагента').item.json.signatoryName;
const signatoryTitle   = $('Собрать данные контрагента').item.json.signatoryTitle || '';
const docId            = $('Скопировать шаблон в папку клиента').item.json.id;

const body = {
  requests: [
    { replaceAllText: { containsText: { text: '{{НОМЕР_ПРИЛОЖЕНИЯ}}',      matchCase: true }, replaceText: nomerPrilozhenia } },
    { replaceAllText: { containsText: { text: '{{НОМЕР_ДОГОВОРА}}',        matchCase: true }, replaceText: nomerDogovora } },
    { replaceAllText: { containsText: { text: '{{ДАТА_ДОГОВОРА}}',         matchCase: true }, replaceText: dataDogovora } },
    { replaceAllText: { containsText: { text: '{{ДАТА_ПРИЛОЖЕНИЯ}}',       matchCase: true }, replaceText: dateApp } },
    { replaceAllText: { containsText: { text: '{{ДАТА_НАЧАЛА_РАБОТ}}',     matchCase: true }, replaceText: dateStart } },
    { replaceAllText: { containsText: { text: '{{НАЗВАНИЕ_КЛИЕНТА}}',      matchCase: true }, replaceText: clientName } },
    { replaceAllText: { containsText: { text: '{{ФИО_ПОДПИСАНТА_КЛИЕНТА}}',matchCase: true }, replaceText: signatoryName } },
    { replaceAllText: { containsText: { text: '{{ДОЛЖНОСТЬ_ПОДПИСАНТА}}',  matchCase: true }, replaceText: signatoryTitle } }
  ]
};

return [{ json: { docId, batchBody: JSON.stringify(body) } }];
